$_tipsdb['EDTP:allowBrowse'] = array('Der Static-Kontext kann eine URI einem Verzeichnis innerhalb oder ausserhalb des document root zuordnen. Das Verzeichnis kann absolut oder relativ zum document root (Standard), $VH_ROOT oder $SERVER_ROOT sein. Wenn &quot;Accessible&quot; aktiviert ist, koennen statische Dateien in diesem Kontext durchsucht werden. Sie koennen dies deaktivieren, um das Anzeigen statischer Dateien zu verhindern.');
