$_tipsdb['EDTP:checkSymbolLink'] = array('Die Check-Symbolic-Link-Steuerung wirkt nur, wenn Follow-Symbolic-Link eingeschaltet ist. Sie steuert, ob symbolische Links gegen Verzeichnisse mit verweigertem Zugriff geprüft werden.');
$_tipsdb['EDTP:compressibleTypes'] = array('Compressible Types ist eine durch Kommas getrennte Liste komprimierbarer MIME-Typen. Sie können den Platzhalter &quot;*&quot; für MIME-Typen verwenden, z. B. */*, text/*. Sie können &quot;!&quot; voranstellen, um bestimmte Typen auszuschließen. Die Reihenfolge der Liste ist wichtig, wenn Sie &quot;!&quot; verwenden. Zum Beispiel komprimiert eine Liste wie &quot;text/*, !text/css, !text/js&quot; alle Textdateien außer css und js.');
$_tipsdb['EDTP:ctxType'] = array('Waehlen Sie den Kontexttyp, der zu der Ressource oder Anwendung passt, die Sie einbinden moechten.');
$_tipsdb['EDTP:docRoot'] = array('Der Dokumentstamm wird vom Server nicht automatisch erstellt, wenn er noch nicht existiert. Stellen Sie sicher, dass das Verzeichnis vorhanden ist und dem richtigen Benutzer gehört.');
$_tipsdb['EDTP:domainName'] = array('Geben Sie alle Domains ein, auf die dieser Listener antworten soll. Verwenden Sie ein Komma &quot;,&quot;, um einzelne Domains zu trennen. Sie koennen einen einzelnen virtuellen Host auswaehlen, der alle nicht angegebenen Domains verarbeitet; setzen Sie dazu &quot;*&quot; in Domains.');
$_tipsdb['EDTP:enableDynGzipCompress'] = array('Die dynamische GZIP-Komprimierungssteuerung ist nur wirksam, wenn GZIP-Komprimierung aktiviert ist.');
$_tipsdb['EDTP:enableExpires'] = array('Expires kann auf Server-/Virtual-Host-/Kontextebene gesetzt werden. Einstellungen niedrigerer Ebenen ueberschreiben hoehere Ebenen. In Bezug auf die Ueberschreibungsprioritaet: <br><br> Kontextebene > Virtual-Host-Ebene > Serverebene <br><br>');
$_tipsdb['EDTP:enableRecaptcha'] = array('Wenn diese Einstellung auf Serverebene auf <b>Yes</b> gesetzt ist, kann CAPTCHA Protection auf Virtual-Host-Ebene weiterhin deaktiviert werden.');
$_tipsdb['EDTP:errURL'] = array('Sie können angepasste Fehlerseiten für verschiedene Fehlercodes einrichten.');
$_tipsdb['EDTP:expiresByType'] = array('Expires By Type ueberschreibt Standardeinstellungen. Jeder Eintrag hat das Format &quot;MIME-type=A|Mseconds&quot; ohne Leerzeichen dazwischen. Sie koennen mehrere Eintraege durch Kommas getrennt eingeben.');
$_tipsdb['EDTP:expiresDefault'] = array('Expires-Syntax &quot;A|Mseconds&quot; bedeutet, dass die Datei nach Basiszeit (A oder M) plus der angegebenen Zeit in Sekunden ablaeuft. &quot;A&quot; bedeutet Client-Zugriffszeit, &quot;M&quot; bedeutet Datei-Aenderungszeit. Sie koennen diese Standardeinstellung fuer verschiedene MIME-Typen ueberschreiben: A86400 bedeutet, dass die Datei nach 1 Tag basierend auf der Client-Zugriffszeit ablaeuft.');
$_tipsdb['EDTP:extAppAddress'] = array('Die Adresse kann eine IPv4-Socket-Adresse &quot;IP:PORT&quot; wie 192.168.1.3:7777 und localhost:7777 oder eine Unix-domain-socket-Adresse &quot;UDS://path&quot; wie UDS://tmp/lshttpd/myfcgi.sock sein. UDS liegt in einer chroot-Umgebung innerhalb des chroot. Fuer lokale Anwendungen wird Unix domain socket wegen Sicherheit und besserer Leistung bevorzugt. Wenn Sie einen IPv4-Socket verwenden muessen, setzen Sie den IP-Teil auf localhost oder 127.0.0.1, damit die Anwendung von anderen Maschinen nicht erreichbar ist.');
$_tipsdb['EDTP:extAppName'] = array('Geben Sie einen leicht zu merkenden Namen an; andere Stellen verweisen mit diesem Namen auf diese App.');
$_tipsdb['EDTP:extAppType'] = array('Sie koennen eine externe Fast CGI-Anwendung und eine mit AJPv13 (Apache JServ Protocol v1.3) kompatible Servlet-Engine konfigurieren.');
$_tipsdb['EDTP:extWorkers'] = array('Load-Balancing-Worker muessen zuvor definiert sein. Verfuegbare ExtApp-Typen sind lsapi(LSAPI App), proxy(Web Server (Proxy)), fcgi(Fast CGI App), scgi(SCGI App), servlet(Servlet/JSP Engine) und uwsgi(uWSGI). Verschiedene Typen externer Anwendungen koennen in einem Load-Balancing-Cluster gemischt werden.');
$_tipsdb['EDTP:externalredirect'] = array('Richten Sie hier die Weiterleitungs-URI ein. Bei externer Weiterleitung koennen Sie den Statuscode angeben. Interne Weiterleitungen muessen mit &quot;/&quot; beginnen; externe koennen mit &quot;/&quot; oder &quot;http(s)://&quot; beginnen.');
$_tipsdb['EDTP:extraHeaders'] = array('Die Einstellung Header Operations ist abwaertskompatibel mit der alten Syntax &#039;header_name: value1,value2,...&#039;, die dem Setzen des Headers und der Werte mit der Direktive &#039;Header&#039; entspricht.');
$_tipsdb['EDTP:fcgiapp'] = array('Der Fast CGI-Kontext ist ein Mount-Punkt fuer eine Fast CGI-Anwendung. Die Fast CGI-Anwendung muss auf Server- oder Virtual-Host-Ebene vordefiniert sein.');
$_tipsdb['EDTP:followSymbolLink'] = array('Wenn Follow-Symbolic-Link aktiviert ist, können Sie es auf Virtual-Host-Ebene weiterhin deaktivieren.');
$_tipsdb['EDTP:gdb_groupname'] = array('Der Gruppenname sollte nur aus Buchstaben und Zahlen bestehen.');
$_tipsdb['EDTP:gzipCompressLevel'] = array('Die GZIP-Komprimierungsstufe reicht von 1 (Minimum) bis 9 (Maximum).');
$_tipsdb['EDTP:hardLimit'] = array('Legt Limits für gleichzeitige Verbindungen von einem Client fest (pro IP-Adresse). Dies hilft gegen DoS-Angriffe.');
$_tipsdb['EDTP:indexUseServer'] = array('Sie können die Standard-Servereinstellungen für Indexdateien verwenden, eigene Einstellungen ergänzen oder Indexdateien deaktivieren, indem Sie die vhost-Einstellung leer lassen.');
