$_tipsdb['EDTP:javaWebApp_location'] = array('Der Java-Web-App-Kontext importiert automatisch eine vordefinierte Java-Anwendung in eine AJPv13-kompatible Servlet-Engine. Die Servlet-Engine muss im Abschnitt fuer externe Anwendungen eingerichtet sein. Der Speicherort ist das Verzeichnis mit den Webanwendungsdateien, einschliesslich des Unterverzeichnisses WEB-INF/.');
