$_tipsdb['EDTP:sslSessionCache'] = array('Sitzungscaching erlaubt einem Client, eine Sitzung innerhalb einer festgelegten Zeit fortzusetzen, ohne einen SSL-Handshake erneut durchführen zu müssen. Dies kann durch Zuweisung einer Sitzungs-ID mit <b>Enable Session Cache</b> oder durch Erstellen und Verwenden von Sitzungstickets erfolgen.');
